// Commit message: list-objects: pass full pathname to callbacks  When we find a blob at "a/b/c", we currently pass this to our show_object_fn callbacks as two components: "a/b/" and "c". Callbacks which want the full value then call path_name(), which concatenates the two. But this is an inefficient interface; the path is a strbuf, and we could simply append "c" to it temporarily, then roll back the length, without creating a new copy.  So we could improve this by teaching the callsites of path_name() this trick 
// Unified diff (vulnerable -> fixed). '-' lines are the VULNERABLE code, '+' are the fix. Classify the weakness in the removed/vulnerable code.
--- vulnerable.c
+++ fixed.c
@@ -1,16 +1,13 @@
 static void show_object(struct object *object, struct strbuf *path,
-			const char *last, void *data)
+static void show_object(struct object *object, const char *name, void *data)
  {
  	struct bitmap *base = data;
  	int bitmap_pos;

  	bitmap_pos = bitmap_position(object->oid.hash);

-	if (bitmap_pos < 0) {
-		char *name = path_name(path, last);
+	if (bitmap_pos < 0)
  		bitmap_pos = ext_index_add_object(object, name);
-		free(name);
-	}

  	bitmap_set(base, bitmap_pos);
  }

